import React, { useState, useEffect } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { AdminService } from '../../../services/api';
import { ArrowLeft, Save, Upload } from 'lucide-react';
import toast from 'react-hot-toast';

const FormField = ({ label, value, onChange, placeholder = "", dir = "ltr" }: any) => (
  <div className="space-y-1">
    <label className="text-[9px] font-black uppercase text-gray-500 ml-1">{label}</label>
    <input value={value || ''} onChange={(e) => onChange(e.target.value)} dir={dir} className="w-full bg-white/5 border border-white/10 p-3 rounded-xl text-xs text-white outline-none focus:border-primary transition-all font-bold" placeholder={placeholder} />
  </div>
);

export const AdminSeriesForm = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const [loading, setLoading] = useState(false);
  const [file, setFile] = useState<File | null>(null);

  const [formData, setFormData] = useState({
    Series_ID: '',
    Series_Title_En: '',
    Series_Title_Ar: '',
    Description_En: '',
    Description_Ar: '',
    Year: '',
    Status: 'Complete'
  });

  useEffect(() => {
    if (id) {
      AdminService.getSeriesById(id).then((res: any) => {
        if (res.data?.data) setFormData(res.data.data);
      });
    }
  }, [id]);

  const handleManualSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    try {
      await AdminService.upsertSeries(formData);
      toast.success("Series Updated");
      navigate('/admin/series');
    } catch (err) { toast.error("Failed"); }
    finally { setLoading(false); }
  };

  const handleExcelImport = async () => {
    if (!file) return toast.error("Select file");
    setLoading(true);
    try {
      await AdminService.importData('series', file);
      toast.success("Bulk Sync Complete");
      navigate('/admin/series');
    } catch (err) { toast.error("Import Failed"); }
    finally { setLoading(false); }
  };

  return (
    <div className="max-w-6xl mx-auto p-6 space-y-8 animate-in fade-in duration-700">
      <div className="flex justify-between items-center">
        <button onClick={() => navigate(-1)} className="flex items-center gap-2 text-gray-500 font-black text-[10px] uppercase tracking-widest hover:text-white transition-colors">
          <ArrowLeft size={14} /> Back to Series
        </button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-8">
        <div className="lg:col-span-3">
          <form onSubmit={handleManualSubmit} className="bg-[#0f0f0f] border border-white/5 rounded-[2.5rem] p-10">
            <h2 className="text-2xl font-black italic uppercase mb-8">{id ? 'Modify' : 'Manual'} <span className="text-primary">Series</span></h2>
            <div className="grid grid-cols-2 gap-6 mb-8">
              <FormField label="Series ID" value={formData.Series_ID} onChange={(v: string) => setFormData({...formData, Series_ID: v})} placeholder="S001" />
              <FormField label="Year" value={formData.Year} onChange={(v: string) => setFormData({...formData, Year: v})} />
              <FormField label="Title (EN)" value={formData.Series_Title_En} onChange={(v: string) => setFormData({...formData, Series_Title_En: v})} />
              <FormField label="Title (AR)" value={formData.Series_Title_Ar} onChange={(v: string) => setFormData({...formData, Series_Title_Ar: v})} dir="rtl" />
            </div>
            <button type="submit" className="bg-primary text-black px-12 py-4 rounded-2xl font-black uppercase text-[10px] tracking-widest">
              <Save size={18} className="inline mr-2" /> Save Series
            </button>
          </form>
        </div>

        {!id && (
          <div className="bg-[#0f0f0f] p-8 rounded-[2.5rem] border border-white/5 text-center h-fit">
            <h3 className="text-xs font-black uppercase italic mb-6">Bulk <span className="text-primary">Sync</span></h3>
            <div className="border-2 border-dashed border-white/10 rounded-2xl p-8 relative mb-4">
              <input type="file" className="absolute inset-0 opacity-0 cursor-pointer" onChange={e => setFile(e.target.files?.[0] || null)} />
              <Upload className="mx-auto text-gray-500 mb-2" size={32} />
              <p className="text-[9px] font-black text-gray-500 uppercase">{file ? file.name : 'Upload Series Tab'}</p>
            </div>
            <button onClick={handleExcelImport} className="w-full bg-white/5 py-4 rounded-2xl text-[9px] font-black uppercase tracking-widest hover:bg-white hover:text-black transition-all">Process</button>
          </div>
        )}
      </div>
    </div>
  );
};
